using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow (uses double → decimal cast since DataRow doesn't support decimal literals) ──

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price returns zero")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity returns zero")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData for decimal precision and complex scenarios ──

    public static IEnumerable<object[]> LargeOrderCases
    {
        get
        {
            yield return new object[] { 0.01m, 10000, 0.07m, 107.00m };
            yield return new object[] { 999.99m, 100, 0.0625m, 106248.9375m };
            yield return new object[] { 49.95m, 1, 0.0m, 49.95m };
        }
    }

    [TestMethod]
    [DynamicData(nameof(LargeOrderCases))]
    [Description("Validates decimal-precise calculations for large or precision-sensitive orders")]
    public void CalculateTotal_WithPrecisionSensitiveInputs_ReturnsExactDecimal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    // ── CalculateTotal: invalid inputs ──

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_WithNegativeInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // ── ApplyDiscount: DynamicData with method source ──

    public static IEnumerable<object[]> DiscountCases()
    {
        yield return new object[] { 100m, 0m, 100m };    // no discount
        yield return new object[] { 100m, 10m, 90m };    // 10% off
        yield return new object[] { 100m, 50m, 50m };    // half off
        yield return new object[] { 100m, 100m, 0m };    // free
        yield return new object[] { 249.99m, 15m, 212.4915m }; // fractional result
        yield return new object[] { 0m, 50m, 0m };       // zero price stays zero
    }

    [TestMethod]
    [DynamicData(nameof(DiscountCases), DynamicDataSourceType.Method)]
    [Description("Covers full discount range from 0% to 100% including fractional prices")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    // ── ApplyDiscount: boundary violations ──

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0% throws")]
    [DataRow(100.01, DisplayName = "Discount above 100% throws")]
    public void ApplyDiscount_WithOutOfRangeDiscount_ThrowsArgumentOutOfRange(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    // ── FormatPrice: DataRow for simple string expectations ──

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD format")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro format")]
    [DataRow(1000.00, "£", "£1000.00", DisplayName = "GBP large value")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(9.999, "$", "$10.00", DisplayName = "Rounds to two decimals")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_WithDefaultCurrency_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.AreEqual("$42.00", result);
    }
}

